import { test, expect } from '@playwright/test';

test('Amazon.sg search for headphones displays results', async ({ page }) => {
  // 1. Launch browser and 2. Navigate to https://www.amazon.sg
  await page.goto('https://www.amazon.sg');

  // 3. Wait for search input (name="field-keywords")
  const searchInput = page.locator('input[name="field-keywords"]');
  await expect(searchInput).toBeVisible();

  // 4. Enter "headphones"
  await searchInput.fill('headphones');

  // 5. Press Enter
  await searchInput.press('Enter');

  // 6. Wait for search results to load
  const results = page.locator('div.s-main-slot div[data-component-type="s-search-result"]');
  await expect(results.first()).toBeVisible({ timeout: 15000 });

  // 7. Validate at least one result is displayed
  await expect(results).toHaveCountGreaterThan(0);

  // 8. Close browser (handled by Playwright test runner)
});
